	"low_disk_space",
	({ availableBytes, thresholdBytes }) => {
		console.warn(
			`[daemon] Low disk space warning: ${availableBytes / 1024 / 1024}MB available (threshold: ${thresholdBytes / 1024 / 1024}MB)`,
		);

		// Evict cached sessions to free memory/disk (up to 3 per relay)
		const MAX_EVICTIONS_PER_RELAY = 3;
		for (const relay of this.projectRelays.values()) {
			for (let i = 0; i < MAX_EVICTIONS_PER_RELAY; i++) {
				const evicted = relay.messageCache.evictOldestSession();
				if (!evicted) break;
				console.log(
					`[daemon] Evicted cached session "${evicted}" to free disk space`,
				);
			}
		}
	},
);

